ALTER TABLE [Sales].[Store] DISABLE TRIGGER ALL;
 
MERGE INTO [Sales].[Store] AS Target
USING (
  SELECT [BusinessEntityID],[Demographics],[ModifiedDate],[Name],[SalesPersonID]
    FROM OPENJSON(@v_json)
    WITH (
           [BusinessEntityID] INT,
           [Demographics] XML([Sales].[StoreSurveySchemaCollection]),
           [ModifiedDate] DATETIME,
           [Name] NAME,
           [rowguid] UNIQUEIDENTIFIER,
           [SalesPersonID] INT
    )
) AS Source
ON Source.[BusinessEntityID] = Target.[BusinessEntityID]


WHEN MATCHED AND (NOT (Target.[BusinessEntityID] = Source.[BusinessEntityID] OR (Target.[BusinessEntityID] IS NULL AND Source.[BusinessEntityID] IS NULL)) AND NOT (CAST(Target.[Demographics] AS NVARCHAR(MAX)) = CAST(Source.[Demographics] AS NVARCHAR(MAX)) OR (Target.[Demographics] IS NULL AND Source.[Demographics] IS NULL)) AND NOT (Target.[ModifiedDate] = Source.[ModifiedDate] OR (Target.[ModifiedDate] IS NULL AND Source.[ModifiedDate] IS NULL)) AND NOT (Target.[Name] = Source.[Name] OR (Target.[Name] IS NULL AND Source.[Name] IS NULL)) AND NOT (Target.[SalesPersonID] = Source.[SalesPersonID] OR (Target.[SalesPersonID] IS NULL AND Source.[SalesPersonID] IS NULL))) THEN
  UPDATE SET
        [BusinessEntityID] = Source.[BusinessEntityID],
        [Demographics] = Source.[Demographics],
        [ModifiedDate] = Source.[ModifiedDate],
        [Name] = Source.[Name],
        [SalesPersonID] = Source.[SalesPersonID]


WHEN NOT MATCHED THEN
  INSERT (
        [BusinessEntityID],
        [Demographics],
        [ModifiedDate],
        [Name],
        [SalesPersonID]
  ) VALUES (
        Source.[BusinessEntityID],
        Source.[Demographics],
        Source.[ModifiedDate],
        Source.[Name],
        Source.[SalesPersonID]  
  )
;
ALTER TABLE [Sales].[Store] ENABLE TRIGGER ALL;
